-- Расширенный глобальный сид-каталог (см. docs/SPEC.md §3.1).
-- Двуязычный (en/uk), с кластером и категорией. Идемпотентно: ON CONFLICT DO UPDATE
-- по уникальному индексу exercises_global_name_uidx (name_en среди is_global),
-- поэтому миграция и заводит новые, и обновляет ранее засеянные 16 упражнений.

on conflict (name_en) where is_global do update set
  name_uk      = excluded.name_uk,
  muscle_group = excluded.muscle_group,
  equipment    = excluded.equipment,
  aliases      = excluded.aliases,
  cluster      = excluded.cluster,
  category     = excluded.category;
